import React, { useEffect, useRef, useState } from 'react';
import io from 'socket.io-client';
import Peer from 'simple-peer';

const VideoCall = ({ roomId, userId, onLeave }) => {
  const [peers, setPeers] = useState([]);
  const [localStream, setLocalStream] = useState(null);
  const [remoteStreams, setRemoteStreams] = useState(new Map());
  const [isAudioEnabled, setIsAudioEnabled] = useState(true);
  const [isVideoEnabled, setIsVideoEnabled] = useState(true);
  const [connectionStatus, setConnectionStatus] = useState('connecting');
  const [socketId, setSocketId] = useState('');
  
  const socketRef = useRef();
  const peersRef = useRef([]);
  const localVideoRef = useRef();
  const remoteVideosRef = useRef(new Map());

  useEffect(() => {
    let isMounted = true;

    const init = async () => {
      try {
        // Connect to signaling server
        socketRef.current = io('http://localhost:3001', {
          transports: ['polling', 'websocket'],
          reconnectionAttempts: 5,
          reconnectionDelay: 1000,
           timeout: 20000,
          forceNew: true
        });

        socketRef.current.on('connect', () => {
          console.log('✅ Socket connected:', socketRef.current.id);
          if (isMounted) {
            setSocketId(socketRef.current.id);
            setConnectionStatus('connected');
          }
        });

        socketRef.current.on('connect_error', (err) => {
          console.error('Socket error:', err);
          if (isMounted) setConnectionStatus('error');
        });

        // Better media access with error handling for Firefox
const constraints = {
  video: {
    width: { ideal: 640 },
    height: { ideal: 480 },
    frameRate: { ideal: 30 },
    // Add Firefox-specific options
    facingMode: "user",
    resizeMode: "crop-and-scale"
  },
  audio: {
    echoCancellation: true,
    noiseSuppression: true,
    autoGainControl: true,
    // Firefox prefers specific audio constraints
    channelCount: 2,
    sampleRate: 48000
  }
};

console.log('Requesting media with constraints:', constraints);

try {
  const stream = await navigator.mediaDevices.getUserMedia(constraints);
  console.log('✅ Got local stream');
  console.log('Video tracks:', stream.getVideoTracks().length);
  console.log('Audio tracks:', stream.getAudioTracks().length);
  
  stream.getVideoTracks().forEach(track => {
    console.log('Video track settings:', track.getSettings());
  });
  
  setLocalStream(stream);
  if (localVideoRef.current) {
    localVideoRef.current.srcObject = stream;
  }

  // Join room after getting stream
  console.log('Emitting join-room event:', { roomId, userId });
  socketRef.current.emit('join-room', { roomId, userId });
  
} catch (error) {
  console.error('❌ Error accessing media devices:', error);
  console.error('Error name:', error.name);
  console.error('Error message:', error.message);
  
  setConnectionStatus('error');
  
  // Show user-friendly message based on error
  if (error.name === 'NotAllowedError' || error.message.includes('perm')) {
    alert('Camera access denied. Please allow camera and microphone access in Firefox:\n\n' +
          '1. Click the camera icon in the address bar\n' +
          '2. Select "Allow" for camera and microphone\n' +
          '3. Refresh the page');
  } else if (error.name === 'NotFoundError') {
    alert('No camera or microphone found. Please connect a camera and try again.');
  } else if (error.name === 'NotReadableError' || error.message.includes('starting')) {
    alert('Camera is already in use by another application. Please close other apps using the camera.');
  } else {
    alert(`Could not access camera/microphone: ${error.message}`);
  }
}
        // Join room after media is ready
        socketRef.current.emit('join-room', { roomId, userId });

        // Handle room events
        socketRef.current.on('room-joined', ({ participants }) => {
          console.log('Joined room, participants:', participants);
          participants.forEach(p => {
            if (p.socketId !== socketRef.current.id) {
              createPeer(p.socketId, true);
            }
          });
        });

        socketRef.current.on('user-connected', ({ socketId }) => {
          console.log('User connected:', socketId);
          createPeer(socketId, false);
        });

        socketRef.current.on('offer', ({ offer, from }) => {
          console.log('Received offer from:', from);
          createPeer(from, false, offer);
        });

        socketRef.current.on('answer', ({ answer, from }) => {
          console.log('Received answer from:', from);
          const peer = peersRef.current.find(p => p.peerID === from);
          if (peer) peer.peer.signal(answer);
        });

        socketRef.current.on('ice-candidate', ({ candidate, from }) => {
          console.log('Received ICE from:', from);
          const peer = peersRef.current.find(p => p.peerID === from);
          if (peer && candidate) peer.peer.signal(candidate);
        });

        socketRef.current.on('user-disconnected', ({ socketId }) => {
          console.log('User disconnected:', socketId);
          const peerIndex = peersRef.current.findIndex(p => p.peerID === socketId);
          if (peerIndex > -1) {
            peersRef.current[peerIndex].peer.destroy();
            peersRef.current.splice(peerIndex, 1);
          }
          remoteVideosRef.current.delete(socketId);
          setPeers(peersRef.current.map(p => p.peerID));
          setRemoteStreams(new Map(remoteVideosRef.current));
        });

          socketRef.current.on('error', ({ message }) => {
            console.error('Room error:', message);
    
            if (message === 'Room not found') {
              alert('This room no longer exists. Please create a new room.');
              // Small delay before leaving
              setTimeout(() => {
              onLeave();
                }, 1000);
            } else if (message === 'Room is full') {
              alert('This room is full. Please try another room or create a new one.');
              setTimeout(() => {
              onLeave();
            }, 1000);
            }
          });

      } catch (err) {
        console.error('Init error:', err);
        if (isMounted) {
          setConnectionStatus('error');
          alert('Failed to access camera/microphone');
        }
      }
    };

    init();

    return () => {
      isMounted = false;
      if (localStream) {
        localStream.getTracks().forEach(t => t.stop());
      }
      peersRef.current.forEach(p => p.peer.destroy());
      if (socketRef.current) {
        socketRef.current.disconnect();
      }
    };
  }, [roomId, userId]);

  const createPeer = (targetSocketId, initiator, offer = null) => {
    if (!localStream) return;

    const peer = new Peer({
      initiator,
      stream: localStream,
      trickle: true,
      config: {
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' }
        ]
      }
    });

    peer.on('signal', signal => {
      if (initiator && !offer) {
        socketRef.current.emit('offer', {
          offer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (offer && signal.type === 'answer') {
        socketRef.current.emit('answer', {
          answer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (signal.type === 'candidate') {
        socketRef.current.emit('ice-candidate', {
          candidate: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      }
    });

    peer.on('stream', stream => {
      console.log('Got stream from:', targetSocketId);
      const videoEl = document.createElement('video');
      videoEl.srcObject = stream;
      videoEl.autoplay = true;
      videoEl.playsInline = true;
      videoEl.className = "w-full h-full object-cover";
      remoteVideosRef.current.set(targetSocketId, videoEl);
      setRemoteStreams(new Map(remoteVideosRef.current));
    });

    peer.on('connect', () => console.log('Peer connected:', targetSocketId));
    peer.on('error', err => console.error('Peer error:', err));

    peersRef.current.push({ peerID: targetSocketId, peer });
    setPeers(peersRef.current.map(p => p.peerID));

    if (offer) peer.signal(offer);
  };

  const toggleAudio = () => {
    if (localStream) {
      localStream.getAudioTracks().forEach(t => t.enabled = !isAudioEnabled);
      setIsAudioEnabled(!isAudioEnabled);
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      localStream.getVideoTracks().forEach(t => t.enabled = !isVideoEnabled);
      setIsVideoEnabled(!isVideoEnabled);
    }
  };

  return (
    <div className="space-y-4">
      {/* Status Bar */}
      <div className="bg-white rounded-lg shadow-md p-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <div className={`h-3 w-3 rounded-full ${
              connectionStatus === 'connected' ? 'bg-green-500' : 
              connectionStatus === 'connecting' ? 'bg-yellow-500' : 'bg-red-500'
            }`} />
            <span className="text-sm font-medium">
              {connectionStatus === 'connected' ? 'Connected' : 
               connectionStatus === 'connecting' ? 'Connecting...' : 'Error'}
            </span>
            <span className="text-sm">Room: {roomId}</span>
            <span className="text-sm">Users: {peers.length + 1}</span>
          </div>
          <button onClick={onLeave} className="bg-red-500 text-white px-4 py-2 rounded">
            Leave
          </button>
        </div>
      </div>

      {/* Video Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-black rounded-lg overflow-hidden aspect-video">
          <video ref={localVideoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
          <div className="absolute bottom-2 left-2 bg-black/70 text-white px-2 py-1 rounded text-xs">
            You {!isVideoEnabled && '(Video Off)'} {!isAudioEnabled && '(Muted)'}
          </div>
        </div>

        {Array.from(remoteStreams).map(([id, videoEl]) => (
          <div key={id} className="bg-black rounded-lg overflow-hidden aspect-video relative">
            <video ref={el => el && !el.srcObject && (el.srcObject = videoEl.srcObject)} 
                   autoPlay playsInline className="w-full h-full object-cover" />
            <div className="absolute bottom-2 left-2 bg-black/70 text-white px-2 py-1 rounded text-xs">
              Participant
            </div>
          </div>
        ))}

        {peers.length === 0 && (
          <div className="bg-gray-800 rounded-lg aspect-video flex items-center justify-center text-gray-400">
            <div className="text-center">
              <p>Waiting for others to join...</p>
              <p className="text-sm mt-2">Room ID: {roomId}</p>
            </div>
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="bg-white rounded-lg shadow-md p-4 flex justify-center space-x-4">
        <button onClick={toggleAudio} 
                className={`p-3 rounded-full ${isAudioEnabled ? 'bg-blue-500' : 'bg-red-500'} text-white`}>
          {isAudioEnabled ? '🔊' : '🔇'}
        </button>
        <button onClick={toggleVideo}
                className={`p-3 rounded-full ${isVideoEnabled ? 'bg-blue-500' : 'bg-red-500'} text-white`}>
          {isVideoEnabled ? '📹' : '🚫'}
        </button>
      </div>

      {/* Debug */}
      {process.env.NODE_ENV === 'development' && (
        <div className="bg-gray-900 text-green-400 p-4 rounded-lg text-xs">
          <div>Socket: {socketId || 'No ID'}</div>
          <div>Status: {connectionStatus}</div>
          <div>Peers: {peers.length}</div>
        </div>
      )}
    </div>
  );
};

export default VideoCall;
